import React, { useState } from 'react';
import Select from 'react-select';
import { useNavigate } from 'react-router-dom';


import './AddMaterial.css';


const AddMaterial = ({ handleAdd, vendors }) => {

  const navigate = useNavigate();

  const [newMaterial, setNewMaterial] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: null,
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewMaterial((prevMaterial) => ({
      ...prevMaterial,
      [name]: value,
    }));
  };

  const handleVendorChange = (selectedOption) => {
    if (selectedOption && selectedOption.value === '+') {
      navigate('/AddVendor', {
        state: { addMaterialCallback: handleAddVendorCallback },
      });
    } else {
      setNewMaterial((prevMaterial) => ({
        ...prevMaterial,
        recent_vendor: selectedOption,
      }));
    }
  };

  const handleAddVendorCallback = (newVendor) => {
    setNewMaterial((prevMaterial) => ({
      ...prevMaterial,
      recent_vendor: { value: newVendor.id, label: newVendor.name },
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAdd(newMaterial);
    resetForm();
  };

  const resetForm = () => {
    setNewMaterial({
      matid: '',
      name: '',
      description: '',
      unit_of_measure: '',
      price_per_unit: 0,
      recent_vendor: null,
    });
  };

  const vendorOptions = [
    { value: '+', label: '+ Add New Vendor' }, // Add the "+" sign as an option
    ...vendors.map((vendor) => ({ value: vendor.vendorid, label: vendor.name })),
  ];

  const filterOption = (option, inputValue) => {
    if (option.value === '+') {
      return true; // Always show the "+" option
    }
    return option.label.toLowerCase().includes(inputValue.toLowerCase());
  };

  
  return (
    <div className="add-material-container">
      <h2 className="add-material-heading">Add Material</h2>
      <form className="add-material-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="matid">Material ID:</label>
            <input
              type="text"
              id="matid"
              name="matid"
              value={newMaterial.matid}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              name="name"
              value={newMaterial.name}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <textarea
              id="description"
              name="description"
              value={newMaterial.description}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="unit_of_measure">Unit of Measure:</label>
            <input
              type="text"
              id="unit_of_measure"
              name="unit_of_measure"
              value={newMaterial.unit_of_measure}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="price_per_unit">Price per Unit:</label>
            <input
              type="number"
              id="price_per_unit"
              name="price_per_unit"
              value={newMaterial.price_per_unit}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="recent_vendor" className="vendor-label">
              Recent Vendor:
            </label>
            <Select
              id="recent_vendor"
              name="recent_vendor"
              value={newMaterial.recent_vendor}
              onChange={handleVendorChange}
              options={vendorOptions}
              isClearable={true}
              placeholder="Select a vendor"
              required
              filterOption={filterOption} // Exclude the "+" option from filtering
            />
        </div>
        </div>
        <button type="submit" className="add-material-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default AddMaterial;
